import { useState } from "react";
import { supabase } from "../services/supabaseClient";
import { useNavigate } from "react-router-dom";

function Auth({ setUser }) {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [isLogin, setIsLogin] = useState(true);

  const navigate = useNavigate();

  const handleSignup = async () => {
    const { error } = await supabase.auth.signUp({ email, password });
    if (error) alert(error.message);
    else {
      alert("Signup successful ✅");
      setIsLogin(true);
    }
  };

  const handleLogin = async () => {
    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });

    if (error) alert(error.message);
    else {
      setUser(data.user);
      navigate("/");
    }
  };

  const handleGoogleLogin = async () => {
    await supabase.auth.signInWithOAuth({
      provider: "google",
    });
  };

  return (
    <div className="h-screen flex items-center justify-center bg-gradient-to-br from-slate-50 via-blue-50 to-indigo-100 dark:from-gray-900 dark:via-slate-900 dark:to-gray-950">
      {/* GLASS CARD */}
      <div className="backdrop-blur-lg bg-white/80 dark:bg-gray-800/80 border border-white/40 dark:border-gray-600 p-8 rounded-2xl shadow-2xl w-[360px] transition-all duration-300 hover:scale-105">
        {/* TITLE */}
        <h2 className="text-2xl font-bold text-center mb-6 text-gray-800 dark:text-gray-200">
          {isLogin ? "Welcome Back 👋" : "Create Account 🚀"}
        </h2>

        {/* EMAIL */}
        <input
          type="email"
          placeholder="Email"
          className="w-full p-3 mb-3 rounded-lg bg-white/90 dark:bg-gray-700/90 border border-white/50 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-400 dark:focus:ring-indigo-500 text-gray-800 dark:text-gray-200 placeholder-gray-500 dark:placeholder-gray-400"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        {/* PASSWORD */}
        <input
          type="password"
          placeholder="Password"
          className="w-full p-3 mb-4 rounded-lg bg-white/90 dark:bg-gray-700/90 border border-white/50 dark:border-gray-600 focus:outline-none focus:ring-2 focus:ring-indigo-400 dark:focus:ring-indigo-500 text-gray-800 dark:text-gray-200 placeholder-gray-500 dark:placeholder-gray-400"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        {/* MAIN BUTTON */}
        <button
          onClick={isLogin ? handleLogin : handleSignup}
          className="w-full bg-gradient-to-r from-indigo-600 to-purple-600 text-white py-3 rounded-lg hover:from-indigo-700 hover:to-purple-700 transition-all duration-300 font-semibold shadow-lg hover:shadow-xl"
        >
          {isLogin ? "Login" : "Sign Up"}
        </button>

        {/* DIVIDER */}
        <div className="text-center my-4 text-gray-500 dark:text-gray-400">or</div>

        {/* GOOGLE - only for signup */}
        {!isLogin && (
          <button
            onClick={handleGoogleLogin}
            className="w-full bg-white/90 dark:bg-gray-700/90 py-3 rounded-lg hover:bg-white dark:hover:bg-gray-600 transition-all duration-300 border border-gray-200 dark:border-gray-600 shadow-sm hover:shadow-md flex items-center justify-center gap-2"
          >
            <img src="https://authjs.dev/img/providers/google.svg" alt="Google" className="h-5 w-5" />
            Continue with Google
          </button>
        )} 

        {/* TOGGLE */}
        <p className="text-center mt-4 text-sm text-gray-700 dark:text-gray-300">
          {isLogin ? "Don't have an account?" : "Already have an account?"}
          <span
            onClick={() => setIsLogin(!isLogin)}
            className="text-indigo-600 dark:text-indigo-400 ml-2 cursor-pointer font-medium hover:underline"
          >
            {isLogin ? "Sign Up" : "Login"}
          </span>
        </p>

      </div>
    </div>
  );
}

export default Auth;
